/**
 * TaskGrid — the left-side task table (MS Project style).
 *
 * Flat table with virtual-ish rendering, inline editing,
 * expand/collapse for summary tasks, selection.
 */

import React, { useState, useMemo, useCallback } from 'react';
import {
  Table,
  TableHead,
  TableBody,
  TableRow,
  TableCell,
  TableContainer,
  Box,
  Typography,
} from '@mui/material';

import TaskRowComponent from './TaskRow';
import { useProjectStore, type TaskRow } from '../../stores';

const TaskGrid: React.FC = () => {
  const tasks = useProjectStore((s) => s.tasks);
  const selectedTaskIds = useProjectStore((s) => s.selectedTaskIds);
  const [collapsedIds, setCollapsedIds] = useState<Set<string>>(new Set());

  // Determine which tasks have children
  const childMap = useMemo(() => {
    const map = new Set<string>();
    for (const t of tasks) {
      if (t.parentId) map.add(t.parentId);
    }
    return map;
  }, [tasks]);

  // Build collapsed ancestor set for hiding children
  const hiddenIds = useMemo(() => {
    const hidden = new Set<string>();
    // For each collapsed task, hide all descendants
    const taskById = new Map(tasks.map((t) => [t.id, t]));
    for (const t of tasks) {
      let cur = t.parentId;
      while (cur) {
        if (collapsedIds.has(cur)) {
          hidden.add(t.id);
          break;
        }
        const parent = taskById.get(cur);
        cur = parent?.parentId ?? null;
      }
    }
    return hidden;
  }, [tasks, collapsedIds]);

  const visibleTasks = useMemo(
    () => tasks.filter((t) => !hiddenIds.has(t.id)),
    [tasks, hiddenIds],
  );

  const toggleExpand = useCallback((taskId: string) => {
    setCollapsedIds((prev) => {
      const next = new Set(prev);
      if (next.has(taskId)) next.delete(taskId);
      else next.add(taskId);
      return next;
    });
  }, []);

  if (tasks.length === 0) {
    return (
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          height: '100%',
          color: 'text.secondary',
        }}
      >
        <Typography variant="body2">No tasks yet. Add a task to begin.</Typography>
      </Box>
    );
  }

  return (
    <TableContainer sx={{ height: '100%', overflow: 'auto' }}>
      <Table size="small" stickyHeader sx={{ tableLayout: 'fixed' }}>
        <TableHead>
          <TableRow>
            <TableCell sx={{ width: 40 }}>#</TableCell>
            <TableCell sx={{ minWidth: 240 }}>Task Name</TableCell>
            <TableCell sx={{ width: 80 }} align="right">
              Duration
            </TableCell>
            <TableCell sx={{ width: 100 }}>Start</TableCell>
            <TableCell sx={{ width: 100 }}>Finish</TableCell>
            <TableCell sx={{ width: 60 }} align="right">
              % Done
            </TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {visibleTasks.map((task, idx) => (
            <TaskRowComponent
              key={task.id}
              task={task}
              index={idx}
              isSelected={selectedTaskIds.has(task.id)}
              isExpanded={!collapsedIds.has(task.id)}
              hasChildren={childMap.has(task.id)}
              onToggleExpand={toggleExpand}
            />
          ))}
        </TableBody>
      </Table>
    </TableContainer>
  );
};

export default TaskGrid;
